import { useState } from "react";

const WINNING_LINES = [
  [[0, 0], [0, 1], [0, 2]],
  [[1, 0], [1, 1], [1, 2]],
  [[2, 0], [2, 1], [2, 2]],
  [[0, 0], [1, 0], [2, 0]],
  [[0, 1], [1, 1], [2, 1]],
  [[0, 2], [1, 2], [2, 2]],
  [[0, 0], [1, 1], [2, 2]],
  [[0, 2], [1, 1], [2, 0]],
];

function emptyBoard() {
  return [
    [" ", " ", " "],
    [" ", " ", " "],
    [" ", " ", " "],
  ];
}

function move(board, row, col, player) {
  if (board[row][col]) {
    return board;
  }

  const nextBoard = board.map((row) => [...row]);
  nextBoard[row][col] = player;

  return nextBoard;
}

function findWinner(board) {
  for (const [a, b, c] of WINNING_LINES) {
    const player = board[a[0]][a[1]];

    if (
      player &&
      player === board[b[0]][b[1]] &&
      player === board[c[0]][c[1]]
    ) {
      return player;
    }
  }

  return null;
}

export default function TicTacToe() {
  const [board, setBoard] = useState(emptyBoard());
  const [turn, setTurn] = useState("X");

  const winner = findWinner(board);

  function play(row, col) {
    if (winner) return;

    const nextBoard = move(board, row, col, turn);

    if (nextBoard === board) return;

    setBoard(nextBoard);
    setTurn(turn === "X" ? "O" : "X");
  }

  function reset() {
    setBoard(emptyBoard());
    setTurn("X");
  }

  return (
    <main>
      <h1>Tic Tac Toe</h1>

      <p>{winner ? `${winner} wins!` : `Turn: ${turn}`}</p>

      <table
        style={{
          borderCollapse: "collapse",
        }}
      >
        <tbody>
          {board.map((row, r) => (
            <tr key={r}>
              {row.map((cell, c) => (
                <td
                  key={c}
                  onClick={() => play(r, c)}
                  style={{
                    width: "3rem",
                    height: "3rem",
                    border: "1px solid",
                    textAlign: "center",
                    fontSize: "2rem",
                    cursor: "pointer",
                    userSelect: "none",
                  }}
                >
                  {cell}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>

      <p>
        <button onClick={reset}>Play Again</button>
      </p>
    </main>
  );
}
